package net.evarius.terranexus.item.custom;
import net.evarius.terranexus.config.ConfigManager;import net.evarius.terranexus.identity.AuthorityState;import net.evarius.terranexus.landlord.LandSelectionState;import net.evarius.terranexus.landlord.LandVisuals;import net.minecraft.item.Item;import net.minecraft.item.ItemUsageContext;import net.minecraft.server.network.ServerPlayerEntity;import net.minecraft.text.Text;import net.minecraft.util.ActionResult;import net.minecraft.util.Formatting;
public class LandSurveyToolItem extends Item {public LandSurveyToolItem(Settings settings){super(settings);}@Override public ActionResult useOnBlock(ItemUsageContext context){if(!context.getWorld().isClient()&&context.getPlayer() instanceof ServerPlayerEntity player){if(!AuthorityState.maySurveyLand(player)){player.sendMessage(Text.literal("Keine Vermessungsberechtigung.").formatted(Formatting.RED),true);return ActionResult.FAIL;}LandSelectionState selections=LandSelectionState.get(player.getServer());String dimension=player.getWorld().getRegistryKey().getValue().toString();if(selections.add(player.getUuid(),dimension,context.getBlockPos())){int count=selections.points(player.getUuid()).size();player.sendMessage(Text.literal("Vermessungspunkt "+count+" gesetzt. Linksklick nimmt den letzten Punkt zurück.").formatted(Formatting.GREEN),true);LandVisuals.preview(player,selections.points(player.getUuid()));}else if(selections.get(player.getUuid())!=null&&selections.points(player.getUuid()).size()>=ConfigManager.claims().maximumPolygonPoints)player.sendMessage(Text.literal("Die konfigurierte Höchstzahl an Vermessungspunkten ist erreicht.").formatted(Formatting.RED),true);else player.sendMessage(Text.literal("Starte zuerst eine Freiformvermessung im Bauamt.").formatted(Formatting.RED),true);}return ActionResult.SUCCESS;}}
